tasks = []

def show_tasks(tasks, filter_done=None):
    filtered = [t for t in tasks if filter_done is None or t["done"] == filter_done]
    if not filtered:
        print("Задач нет.")
        return
    for i, t in enumerate(filtered, 1):
        status = "✅" if t["done"] else "⬜"
        print(f"{i}. {status} [{t['priority']}] {t['title']}")

while True:
    print("\n1-Добавить | 2-Выполнить | 3-Удалить | 4-Все | 5-Активные | 6-Выйти")
    choice = input("Выберите: ")

    if choice == "1":
        title = input("Название: ")
        priority = input("Приоритет (низкий/средний/высокий): ")
        tasks.append({"title": title, "priority": priority, "done": False})
    elif choice == "2":
        show_tasks(tasks)
        idx = int(input("Номер задачи: ")) - 1
        tasks[idx]["done"] = True
    elif choice == "3":
        show_tasks(tasks)
        idx = int(input("Номер задачи: ")) - 1
        tasks.pop(idx)
    elif choice == "4":
        show_tasks(tasks)
    elif choice == "5":
        show_tasks(tasks, filter_done=False)
    elif choice == "6":
        break
